// ---------------------------------------------------------------------------
// Stub LandingGitOps for pre-claim hook unit tests.
// ---------------------------------------------------------------------------

// stubLandingGitOps is a minimal implementation of agent.LandingGitOps that
// lets tests inject controlled return values for CurrentBranch and
// FetchOriginAncestryCheck. All other methods panic so unexpected calls are
// caught immediately.
type stubLandingGitOps struct {
	currentBranchFn           func(dir string) (string, error)
	fetchOriginAncestryCheckFn func(dir, branch string) (agent.PreClaimResult, error)
}

func (s stubLandingGitOps) CurrentBranch(dir string) (string, error) {
	if s.currentBranchFn != nil {
		return s.currentBranchFn(dir)
	}
	return "main", nil
}

func (s stubLandingGitOps) FetchOriginAncestryCheck(dir, branch string) (agent.PreClaimResult, error) {
	if s.fetchOriginAncestryCheckFn != nil {
		return s.fetchOriginAncestryCheckFn(dir, branch)
	}
	return agent.PreClaimResult{Action: "unchanged"}, nil
}

func (s stubLandingGitOps) HasRemote(dir, remote string) bool          { panic("unexpected") }
func (s stubLandingGitOps) FetchBranch(dir, remote, branch string) error { panic("unexpected") }
func (s stubLandingGitOps) ResolveRef(dir, ref string) (string, error)  { panic("unexpected") }
func (s stubLandingGitOps) UpdateRefTo(dir, ref, sha, oldSHA string) error { panic("unexpected") }
func (s stubLandingGitOps) SyncWorkTreeToHead(dir, fromRev string) error { panic("unexpected") }
func (s stubLandingGitOps) AddWorktree(dir, path, rev string) error      { panic("unexpected") }
func (s stubLandingGitOps) AddBranchWorktree(dir, path, branch string) error { panic("unexpected") }
func (s stubLandingGitOps) RemoveWorktree(dir, path string) error        { panic("unexpected") }
func (s stubLandingGitOps) MergeInto(wtDir, srcRev, msg string) error    { panic("unexpected") }
func (s stubLandingGitOps) HeadRevAt(dir string) (string, error)         { panic("unexpected") }
func (s stubLandingGitOps) PushFFOnly(dir, remote, localRef, branch string) error { panic("unexpected") }
func (s stubLandingGitOps) CountCommits(dir, base, tip string) int       { panic("unexpected") }
func (s stubLandingGitOps) StageDir(dir, relPath string) error           { panic("unexpected") }
func (s stubLandingGitOps) CommitStaged(dir, msg string) (string, error) { panic("unexpected") }
func (s stubLandingGitOps) DiffNumstat(dir, base, tip string) (string, error) { panic("unexpected") }
func (s stubLandingGitOps) DiffNameOnly(dir, base, tip string) ([]string, error) { panic("unexpected") }

// ---------------------------------------------------------------------------
// Tests
// ---------------------------------------------------------------------------

// TestServerPreClaimHook_PropagatesStagedMainWorktreeError verifies that a
// local worktree safety error (e.g. staged changes, wrong branch) returned by
// FetchOriginAncestryCheck is propagated rather than swallowed by the server
// pre-claim hook.
func TestServerPreClaimHook_PropagatesStagedMainWorktreeError(t *testing.T) {
	localSafetyErr := errors.New("main worktree has staged changes; stash or commit before claiming")

	ops := stubLandingGitOps{
		fetchOriginAncestryCheckFn: func(dir, branch string) (agent.PreClaimResult, error) {
			return agent.PreClaimResult{}, localSafetyErr
		},
	}

	hook := buildPreClaimHook("/fake/root", ops)
	err := hook(context.Background())

	require.Error(t, err, "server hook must propagate local worktree safety errors")
	assert.ErrorIs(t, err, localSafetyErr)
}

// TestServerPreClaimHook_IgnoresGitFetchOriginFailure verifies that a genuine
// "git fetch origin" failure is treated as non-fatal by the server pre-claim
// hook (air-gap friendly).
func TestServerPreClaimHook_IgnoresGitFetchOriginFailure(t *testing.T) {
	fetchErr := fmt.Errorf("git fetch origin main: unable to connect to remote: %w", errors.New("network unreachable"))

	ops := stubLandingGitOps{
		fetchOriginAncestryCheckFn: func(dir, branch string) (agent.PreClaimResult, error) {
			return agent.PreClaimResult{}, fetchErr
		},
	}

	hook := buildPreClaimHook("/fake/root", ops)
	err := hook(context.Background())

	require.NoError(t, err, "server hook must not block on git fetch origin failures")
}

// TestCLIServerPreClaimHook_ErrorPolicyParity verifies that the CLI and server
// pre-claim hooks apply identical error classification: only "git fetch origin"
// errors are non-fatal; all other errors block the claim. This test acts as a
// regression guard preventing the two hooks from drifting apart.
func TestCLIServerPreClaimHook_ErrorPolicyParity(t *testing.T) {
	cases := []struct {
		name        string
		err         error
		wantBlocked bool
	}{
		{
			name:        "git fetch origin failure is non-fatal",
			err:         fmt.Errorf("git fetch origin main: connection refused"),
			wantBlocked: false,
		},
		{
			name:        "local staged-changes safety error blocks",
			err:         errors.New("main worktree has staged changes"),
			wantBlocked: true,
		},
		{
			name:        "local wrong-branch safety error blocks",
			err:         errors.New("main worktree is on branch feature/foo, expected main"),
			wantBlocked: true,
		},
		{
			name:        "detached HEAD safety error blocks",
			err:         errors.New("HEAD is detached at abc1234"),
			wantBlocked: true,
		},
		{
			name:        "git lock file error blocks",
			err:         errors.New("unable to acquire git lock: .git/index.lock exists"),
			wantBlocked: true,
		},
	}

	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			ops := stubLandingGitOps{
				fetchOriginAncestryCheckFn: func(dir, branch string) (agent.PreClaimResult, error) {
					return agent.PreClaimResult{}, tc.err
				},
			}

			serverHook := buildPreClaimHook("/fake/root", ops)
			serverErr := serverHook(context.Background())

			// Verify both hooks agree on whether the error is fatal.
			serverBlocks := serverErr != nil
			cliBlocks := !agent.IsFetchOriginError(tc.err) // mirrors buildCLIPreClaimHook logic

			assert.Equal(t, tc.wantBlocked, serverBlocks,
				"server hook: %s", tc.name)
			assert.Equal(t, tc.wantBlocked, cliBlocks,
				"CLI hook (via IsFetchOriginError): %s", tc.name)
			assert.Equal(t, serverBlocks, cliBlocks,
				"CLI and server hooks must agree: %s", tc.name)
		})
	}
}

